import heapq
class Solution:
    def totalCost(self, costs, k, candidates):
        n = len(costs)
        left = 0
        right = n - 1
        front = []
        back = []
        for _ in range(candidates):
            if left <= right:
                heapq.heappush(front, costs[left])
                left += 1
        for _ in range(candidates):
            if left <= right:
                heapq.heappush(back, costs[right])
                right -= 1
        total = 0
        for _ in range(k):
            if front and (not back or front[0] <= back[0]):
                total += heapq.heappop(front)
                if left <= right:
                    heapq.heappush(front, costs[left])
                    left += 1
            else:
                total += heapq.heappop(back)
                if left <= right:
                    heapq.heappush(back, costs[right])
                    right -= 1
        return total

