class MinHeap {
    constructor() { this.h = []; }
    size() { return this.h.length; }
    top() { return this.h[0]; }
    push(v) {
        const h = this.h; h.push(v);
        let i = h.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (h[p] <= h[i]) break;
            [h[p], h[i]] = [h[i], h[p]]; i = p;
        }
    }
    pop() {
        const h = this.h;
        const top = h[0];
        const last = h.pop();
        if (h.length) {
            h[0] = last;
            let i = 0;
            const n = h.length;
            while (true) {
                let s = i; const l = 2 * i + 1, r = 2 * i + 2;
                if (l < n && h[l] < h[s]) s = l;
                if (r < n && h[r] < h[s]) s = r;
                if (s === i) break;
                [h[s], h[i]] = [h[i], h[s]]; i = s;
            }
        }
        return top;
    }
}
var totalCost = function(costs, k, candidates) {
    const n = costs.length;
    let left = 0, right = n - 1;
    const front = new MinHeap(), back = new MinHeap();
    for (let i = 0; i < candidates && left <= right; i++) { front.push(costs[left++]); }
    for (let i = 0; i < candidates && left <= right; i++) { back.push(costs[right--]); }
    let total = 0;
    for (let i = 0; i < k; i++) {
        if (front.size() && (!back.size() || front.top() <= back.top())) {
            total += front.pop();
            if (left <= right) front.push(costs[left++]);
        } else {
            total += back.pop();
            if (left <= right) back.push(costs[right--]);
        }
    }
    return total;
};
